57: /**
58:  * A class which encapsulates the configuration and the ACL data owned by StandardAuthorizer.
59:  *
60:  * The class is not thread-safe.
61:  */
62: public class StandardAuthorizerData {
63:     /**
64:      * The host or name string used in ACLs that match any host or name.
65:      */
66:     public static final String WILDCARD = "*";
67: 
68:     /**
69:      * The principal entry used in ACLs that match any principal.
70:      */
71:     public static final String WILDCARD_PRINCIPAL = "User:*";
72:     public static final KafkaPrincipal WILDCARD_KAFKA_PRINCIPAL = new KafkaPrincipal(KafkaPrincipal.USER_TYPE, "*");
73: 
74:     /**
75:      * The logger to use.
76:      */
77:     final Logger log;
78: 
79:     /**
80:      * Logger to use for auditing.
81:      */
82:     final Logger auditLog;
83: 
84:     /**
85:      * The current AclMutator.
86:      */
87:     final AclMutator aclMutator;
88: 
89:     /**
90:      * True if the authorizer loading process is complete.
91:      */
92:     final boolean loadingComplete;
93: 
94:     /**
95:      * A statically configured set of users that are authorized to do anything.
96:      */
97:     private final Set<String> superUsers;
98: 
99:     /**
100:      * The result to return if no ACLs match.
101:      */
102:     private final DefaultRule noAclRule;
103: 
104:     /**
105:      * Contains all of the current ACLs
106:      */
107:     private AclCache aclCache;
108: 
109: 
110: 
111:     private static Logger createLogger(int nodeId) {
112:         return new LogContext("[StandardAuthorizer " + nodeId + "] ").logger(StandardAuthorizerData.class);
113:     }
114: 
115:     private static Logger auditLogger() {
116:         return LoggerFactory.getLogger("kafka.authorizer.logger");
117:     }
118: 
119:     static StandardAuthorizerData createEmpty() {
120:         return new StandardAuthorizerData(createLogger(-1),
121:             null,
122:             false,
123:             Set.of(),
124:             DENIED,
125:             new AclCache());
126:     }
127: 
128:     private StandardAuthorizerData(Logger log,
129:                                    AclMutator aclMutator,
130:                                    boolean loadingComplete,
131:                                    Set<String> superUsers,
132:                                    AuthorizationResult defaultResult,
133:                                    AclCache aclCache) {
134:         this.log = log;
135:         this.auditLog = auditLogger();
136:         this.aclMutator = aclMutator;
137:         this.loadingComplete = loadingComplete;
138:         this.superUsers = superUsers;
139:         this.noAclRule = new DefaultRule(defaultResult);
140:         this.aclCache = aclCache;
141:     }
142: 
143:     StandardAuthorizerData copyWithNewAclMutator(AclMutator newAclMutator) {
144:         return new StandardAuthorizerData(
145:             log,
146:             newAclMutator,
147:             loadingComplete,
148:             superUsers,
149:             noAclRule.result,
150:             aclCache);
151:     }
152: 
153:     StandardAuthorizerData copyWithNewLoadingComplete(boolean newLoadingComplete) {
154:         return new StandardAuthorizerData(log,
155:             aclMutator,
156:             newLoadingComplete,
157:             superUsers,
158:             noAclRule.result,
159:             aclCache);
160:     }
161: 
162:     StandardAuthorizerData copyWithNewConfig(int nodeId,
163:                                              Set<String> newSuperUsers,
164:                                              AuthorizationResult newDefaultResult) {
165:         return new StandardAuthorizerData(
166:             createLogger(nodeId),
167:             aclMutator,
168:             loadingComplete,
169:             newSuperUsers,
170:             newDefaultResult,
171:             aclCache);
172:     }
173: 
174:     StandardAuthorizerData copyWithNewAcls(AclCache aclCache) {
175:         StandardAuthorizerData newData =  new StandardAuthorizerData(
176:             log,
177:             aclMutator,
178:             loadingComplete,
179:             superUsers,
180:             noAclRule.result,
181:             aclCache);
182:         log.info("Initialized with {} acl(s).", aclCache.count());
183:         return newData;
184:     }
