186:     void addAcl(Uuid id, StandardAcl acl) {
187:         try {
188:             aclCache = aclCache.addAcl(id, acl);
189:             log.trace("Added ACL {}: {}", id, acl);
190:         } catch (Throwable e) {
191:             log.error("addAcl error", e);
192:             throw e;
193:         }
194:     }
195: 
196:     void removeAcl(Uuid id) {
197:         try {
198:             AclCache aclCacheSnapshot = aclCache.removeAcl(id);
199:             log.trace("Removed ACL {}: {}", id, aclCacheSnapshot.getAcl(id));
200:             aclCache = aclCacheSnapshot;
201:         } catch (Throwable e) {
202:             log.error("removeAcl error", e);
203:             throw e;
204:         }
