273:     private void appendResourcePattern(ResourcePattern resourcePattern, StringBuilder bldr) {
274:         bldr.append(SecurityUtils.resourceTypeName(resourcePattern.resourceType()))
275:             .append(":")
276:             .append(resourcePattern.patternType())
277:             .append(":")
278:             .append(resourcePattern.name());
279:     }
