458:     static KafkaPrincipal baseKafkaPrincipal(AuthorizableRequestContext context) {
459:         KafkaPrincipal sessionPrincipal = context.principal();
460:         return sessionPrincipal.getClass().equals(KafkaPrincipal.class)
461:             ? sessionPrincipal
